// // This T-flip-flop toggles its output on every falling edge of the clock when the T input is high.
module T_flip_flop (
    input wire clk,
    input wire reset,
    input wire T,
    output reg Q
);
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            Q <= 0;
        end else if (T) begin
            Q <= ~Q;
        end
    end
endmodule
